if(!window.jQuery)
{
    function PAGetParameterByName(name,url)
    {
        if (!url) url = window.location.href;
        name = name.replace(/[\[\]]/g, "\\$&");
        var regex = new RegExp("[?&]" + name + "(=([^&#]*)|&|#|$)"),
            results = regex.exec(url);
        if (!results) return null;
        if (!results[2]) return '';
        return decodeURIComponent(results[2].replace(/\+/g, " "));
    }

    var fullSrc = document.querySelector('script[src*="autoload.jq.min.js"]').getAttribute('src');
    if(fullSrc.length > 0)
    {
        var jqSrc = PAGetParameterByName('jqSrc',fullSrc);
        var jqVersion = PAGetParameterByName('v',fullSrc);

        if(jqSrc.length > 0)
        {
            document.write('<script src="'+jqSrc+(jqVersion.length > 0 ? '?v='+jqVersion : '')+'"></script>');
        }
    }


}